async function loadAnnouncements(){const types=[['welcome','Welcome','When somebody joins.'],['leave','Leave','When somebody leaves.'],['boost','Boost','When somebody boosts.'],['birthdays','Birthday','At midnight in the selected timezone.']];const box=$('#announcement-cards');box.innerHTML='';for(const [key,title,desc] of types){let d=await api(`/api/guild/${gid()}/settings/${key}`),defaults={welcome:'Welcome {user} to **{server}**!',leave:'**{username}** left the server.',boost:'Thank you for boosting, {user}! 💜',birthdays:'Happy birthday {user}! 🎉'};let el=document.createElement('article');el.className='card announcement-card';el.innerHTML=`<div class="switch-row"><div><h3>${title}</h3><p>${desc}</p></div><input class="switch" type="checkbox" ${d.enabled?'checked':''}></div><label>Channel<select>${ctx.channels.filter(c=>c.type==='text').map(c=>`<option value="${c.id}" ${String(d.channel_id)===c.id?'selected':''}># ${c.name}</option>`).join('')}</select></label>${key==='birthdays'?`<label>Timezone<input class="ann-timezone" value="${d.timezone||'America/New_York'}"></label>`:''}<label>Normal message<textarea class="ann-content" rows="2">${d.content||defaults[key]}</textarea></label><label>Embed title<input class="ann-title" value="${d.embed?.title||''}"></label><label>Embed description<textarea class="ann-description" rows="3">${d.embed?.description||''}</textarea></label><div class="fields two"><label>Color<input class="ann-color" type="color" value="${d.embed?.color||'#5865f2'}"></label><label>Footer<input class="ann-footer" value="${d.embed?.footer||''}"></label></div><label>Author name<input class="ann-author" value="${d.embed?.author||''}"></label><div class="fields two"><label>Large image URL<input class="ann-image" value="${d.embed?.image||''}"></label><label>Thumbnail URL<input class="ann-thumb" value="${d.embed?.thumbnail||''}"></label></div><div class="emoji-strip">${ctx.emojis.map(x=>emojiCard(x,true)).join('')}</div><div class="mini-preview"></div><button>Save ${title}</button>`;const draw=()=>el.querySelector('.mini-preview').innerHTML=discordPreview(el.querySelector('.ann-content').value,el.querySelector('.ann-title').value,el.querySelector('.ann-description').value,[],{color:el.querySelector('.ann-color').value,footer:el.querySelector('.ann-footer').value,image:el.querySelector('.ann-image').value,thumbnail:el.querySelector('.ann-thumb').value,author:el.querySelector('.ann-author').value,author_icon:el.querySelector('.ann-author-icon')?.value||''});el.querySelectorAll('input,textarea').forEach(i=>i.oninput=draw);el.querySelectorAll('[data-code]').forEach(i=>i.onclick=()=>insertEmoji(i.dataset.code,lastTextField));draw();el.querySelector('button:last-child').onclick=async()=>{const payload={enabled:el.querySelector('.switch').checked,channel_id:el.querySelector('select').value,timezone:el.querySelector('.ann-timezone')?.value||'America/New_York',content:el.querySelector('.ann-content').value,embed:{title:el.querySelector('.ann-title').value,description:el.querySelector('.ann-description').value,color:el.querySelector('.ann-color').value,footer:el.querySelector('.ann-footer').value,author:el.querySelector('.ann-author').value,author_icon:el.querySelector('.ann-author-icon')?.value||'',image:el.querySelector('.ann-image').value,thumbnail:el.querySelector('.ann-thumb').value}};await api(`/api/guild/${gid()}/settings/${key}`,'PUT',payload);toast(`${title} saved`)};box.append(el)}}
async function loadActionLogs(){if(!$('#logs-enabled'))return;try{const d=await api(`/api/guild/${gid()}/settings/action_logs`);$('#logs-enabled').checked=!!d.enabled;$('#logs-channel').value=d.channel_id||$('#logs-channel').value;$('#logs-member-join').checked=!!d.member_join;$('#logs-member-leave').checked=!!d.member_leave;$('#logs-message-delete').checked=!!d.message_delete;$('#logs-message-edit').checked=!!d.message_edit;$('#logs-voice').checked=!!d.voice;$('#logs-new-account-days').value=d.new_account_days??7;renderActionLogPreviews()}catch(e){toast(e.message)}}
