function addTicketOption(data={}){const row=document.createElement('div');row.className='builder-row ticket-option';row.innerHTML=`<button type="button" class="remove-option">×</button><div class="fields two"><label>Label<input class="opt-label" value="${escapeHtml(data.label||'Support')}"></label><label>Emoji<input class="opt-emoji" value="${escapeHtml(data.emoji||'')}"></label></div><label>Description<input class="opt-description" maxlength="100" value="${escapeHtml(data.description||'')}"></label><div class="fields two"><label>Category<select class="opt-category">${categoryOptions()}</select></label><label>Staff role<select class="opt-role">${roleOptions()}</select></label></div><label>Channel prefix<input class="opt-prefix" value="${escapeHtml(data.channel_prefix||'ticket')}"></label>`;row.querySelector('.opt-category').value=data.category_id||'';row.querySelector('.opt-role').value=data.staff_role_id||'';row.querySelector('.remove-option').onclick=()=>{row.remove();renderTicketPreviews()};row.querySelectorAll('input,select').forEach(i=>i.oninput=renderTicketPreviews);$('#ticket-options').append(row);renderTicketPreviews()}
function ticketChoices(){return $$('.ticket-option').map(r=>({label:r.querySelector('.opt-label').value,emoji:r.querySelector('.opt-emoji').value,description:r.querySelector('.opt-description').value,category_id:r.querySelector('.opt-category').value,staff_role_id:r.querySelector('.opt-role').value,channel_prefix:r.querySelector('.opt-prefix').value}))}
function addRoleOption(data={}){const row=document.createElement('div');row.className='builder-row role-option';row.innerHTML=`<button type="button" class="remove-option">×</button><div class="fields two"><label>Button/menu label<input class="opt-label" value="${escapeHtml(data.label||'Member')}"></label><label>Emoji<input class="opt-emoji" value="${escapeHtml(data.emoji||'')}"></label></div><label>Description<input class="opt-description" maxlength="100" value="${escapeHtml(data.description||'')}"></label><label>Role to give<select class="opt-role">${roleOptions()}</select></label>`;row.querySelector('.opt-role').value=data.role_id||'';row.querySelector('.remove-option').onclick=()=>{row.remove();renderRolePreview()};row.querySelectorAll('input,select').forEach(i=>i.oninput=renderRolePreview);$('#role-options').append(row);renderRolePreview()}
function roleChoices(){return $$('.role-option').map(r=>({label:r.querySelector('.opt-label').value,emoji:r.querySelector('.opt-emoji').value,description:r.querySelector('.opt-description').value,role_id:r.querySelector('.opt-role').value}))}
function authorExtras(prefix,key){return{author:$('#'+prefix+'-author')?.value||'',author_icon:savedAssetPreviews[key]||$('#'+prefix+'-author-icon')?.value||''}}function authorPayload(prefix,key){return{author:$('#'+prefix+'-author')?.value||'',author_icon:$('#'+prefix+'-author-icon')?.value||'',author_icon_asset:savedAssets[key]||''}}
function renderTicketPreviews(){if(!$('#ticket-previews'))return;const choices=ticketChoices(),mode=$('#ticket-mode').value,menu=mode==='select'?`<div class="discord-select-preview">${renderDiscordText($('#ticket-placeholder').value||'Choose a ticket type')}<span>⌄</span></div><div class="select-preview-options">${choices.map(c=>`<div>${renderDiscordText(c.emoji)} <b>${escapeHtml(c.label)}</b><small>${escapeHtml(c.description)}</small></div>`).join('')}</div>`:'';const controls=mode==='select'?[]:[{label:$('#ticket-label').value||'Open ticket',emoji:$('#ticket-emoji').value}];$('#ticket-previews').innerHTML=`<p class="eyebrow">PANEL PREVIEW</p>${discordPreview($('#ticket-content').value,$('#ticket-title').value,$('#ticket-description').value,controls,{color:$('#ticket-color').value,image:savedAssetPreviews.ticketImage||$('#ticket-image').value,thumbnail:savedAssetPreviews.ticketThumb||$('#ticket-thumb').value,footer:$('#ticket-footer').value,components:menu,...authorExtras('ticket','ticketAuthor')})}<p class="eyebrow preview-gap">FIRST TICKET MESSAGE</p>${discordPreview($('#ticket-open-content').value,$('#ticket-open-title').value,$('#ticket-open-description').value,[{label:'Claim'},{label:'Close',style:'danger'}],{color:$('#ticket-open-color').value,image:savedAssetPreviews.ticketOpenImage||$('#ticket-open-image').value,thumbnail:savedAssetPreviews.ticketOpenThumb||$('#ticket-open-thumb').value,footer:$('#ticket-open-footer').value,...authorExtras('ticket-open','ticketOpenAuthor')})}`}
$$('#tickets input,#tickets textarea,#tickets select').forEach(i=>i.addEventListener('input',renderTicketPreviews));
function renderRolePreview(){if(!$('#role-preview'))return;const choices=roleChoices(),selectMode=$('#rr-mode').value==='select',buttons=selectMode?[]:choices.map(c=>({label:c.label,emoji:c.emoji})),menu=selectMode?`<div class="discord-select-preview">${renderDiscordText($('#rr-placeholder').value||'Choose your roles')}<span>⌄</span></div><div class="select-preview-options">${choices.map(c=>`<div>${renderDiscordText(c.emoji)} <b>${escapeHtml(c.label)}</b><small>${escapeHtml(c.description)}</small></div>`).join('')}</div>`:'';$('#role-preview').innerHTML=`<p class="eyebrow">DISCORD PREVIEW</p>${discordPreview($('#rr-content').value,$('#rr-title').value,$('#rr-description').value,buttons,{color:$('#rr-color').value,image:savedAssetPreviews.roleImage||$('#rr-image').value,thumbnail:savedAssetPreviews.roleThumb||$('#rr-thumb').value,footer:$('#rr-footer').value,components:menu,...authorExtras('rr','roleAuthor')})}`}
$$('#roles input,#roles textarea,#roles select').forEach(i=>i.addEventListener('input',renderRolePreview));
async function createTicketPanel(){try{await api(`/api/guild/${gid()}/ticket-panel`,'POST',{channel_id:$('#ticket-channel').value,mode:$('#ticket-mode').value,placeholder:$('#ticket-placeholder').value,category_id:$('#ticket-category').value,staff_role_id:$('#ticket-role').value,button_label:$('#ticket-label').value,button_emoji:$('#ticket-emoji').value,content:$('#ticket-content').value,embed:{title:$('#ticket-title').value,description:$('#ticket-description').value,color:$('#ticket-color').value,image:$('#ticket-image').value,thumbnail:$('#ticket-thumb').value,image_asset:savedAssets.ticketImage,thumbnail_asset:savedAssets.ticketThumb,footer:$('#ticket-footer').value,...authorPayload('ticket','ticketAuthor')},options:ticketChoices(),open_content:$('#ticket-open-content').value,open_embed:{title:$('#ticket-open-title').value,description:$('#ticket-open-description').value,color:$('#ticket-open-color').value,image:$('#ticket-open-image').value,thumbnail:$('#ticket-open-thumb').value,image_asset:savedAssets.ticketOpenImage,thumbnail_asset:savedAssets.ticketOpenThumb,footer:$('#ticket-open-footer').value,...authorPayload('ticket-open','ticketOpenAuthor')}});toast('Ticket panel published')}catch(e){toast(e.message)}}
async function createReactionPanel(){try{await api(`/api/guild/${gid()}/reaction-panel`,'POST',{channel_id:$('#rr-channel').value,mode:$('#rr-mode').value,placeholder:$('#rr-placeholder').value,content:$('#rr-content').value,embed:{title:$('#rr-title').value,description:$('#rr-description').value,color:$('#rr-color').value,image:$('#rr-image').value,thumbnail:$('#rr-thumb').value,image_asset:savedAssets.roleImage,thumbnail_asset:savedAssets.roleThumb,footer:$('#rr-footer').value,...authorPayload('rr','roleAuthor')},choices:roleChoices()});toast('Role panel published')}catch(e){toast(e.message)}}
async function giveaway(){try{await api(`/api/guild/${gid()}/giveaway`,'POST',{channel_id:$('#giveaway-channel').value,prize:$('#giveaway-prize').value,minutes:$('#giveaway-minutes').value,winners:$('#giveaway-winners').value,entry_emoji:$('#giveaway-emoji')?.value||'🎉',embed:{title:$('#giveaway-title')?.value,color:$('#giveaway-color')?.value,footer:$('#giveaway-footer')?.value,image:$('#giveaway-image')?.value,thumbnail:$('#giveaway-thumb')?.value,image_asset:savedAssets.giveawayImage,thumbnail_asset:savedAssets.giveawayThumb,...authorPayload('giveaway','giveawayAuthor')}});toast('Giveaway started')}catch(e){toast(e.message)}}
function pollValues(){return $$('.poll-option').map(r=>r.querySelector('input').value.trim()).filter(Boolean)}function renderCommunity(){const opts=pollValues().slice(0,5);$('#poll-preview').innerHTML=discordPreview('',$('#poll-question').value||'Poll question',$('#poll-embed-description')?.value||'Choose an option below.',opts.map(label=>({label})),{color:$('#poll-color')?.value,image:savedAssetPreviews.pollImage||$('#poll-image')?.value,thumbnail:savedAssetPreviews.pollThumb||$('#poll-thumb')?.value,footer:$('#poll-footer')?.value,...authorExtras('poll','pollAuthor')});$('#event-preview').innerHTML=discordPreview('', $('#event-name').value||'Scheduled event',`${$('#event-description').value}\nLocation: ${$('#event-location').value||'Not set'} · starts in ${$('#event-start').value||60} minutes`,eventButtons(),{...authorExtras('event','eventAuthor')})}$$('#community input,#community textarea').forEach(i=>i.addEventListener('input',renderCommunity));renderCommunity();
async function createPoll(){try{await api(`/api/guild/${gid()}/poll`,'POST',{channel_id:$('#poll-channel').value,question:$('#poll-question').value,options:pollValues(),embed:{description:$('#poll-embed-description')?.value,color:$('#poll-color')?.value,footer:$('#poll-footer')?.value,image:$('#poll-image')?.value,thumbnail:$('#poll-thumb')?.value,image_asset:savedAssets.pollImage,thumbnail_asset:savedAssets.pollThumb,...authorPayload('poll','pollAuthor')}});toast('Poll published')}catch(e){toast(e.message)}}
async function createEvent(){try{await api(`/api/guild/${gid()}/event`,'POST',{name:$('#event-name').value,description:$('#event-description').value,location:$('#event-location').value,starts_in_minutes:$('#event-start').value,duration_minutes:$('#event-duration').value,channel_id:$('#event-channel')?.value,buttons:eventButtons(),embed:authorPayload('event','eventAuthor')});toast('Discord event created')}catch(e){toast(e.message)}}
async function saveGlue(){try{await api(`/api/guild/${gid()}/glue`,'POST',{channel_id:$('#glue-channel').value,content:$('#glue-content').value,template_enabled:$('#glue-template-enabled')?.checked,template:$('#glue-template')?.value||'',button_label:$('#glue-button-label')?.value||'Show template',button_emoji:$('#glue-button-emoji')?.value||'',embed:{title:$('#glue-title')?.value,description:$('#glue-embed-description')?.value,color:$('#glue-color')?.value,footer:$('#glue-footer')?.value,image:$('#glue-image')?.value,thumbnail:$('#glue-thumb')?.value,image_asset:savedAssets.glueImage,thumbnail_asset:savedAssets.glueThumb,...authorPayload('glue','glueAuthor')}});toast('Glued message enabled')}catch(e){toast(e.message)}}
const gifActions=['hug','kiss','slap','pat','cuddle','bite'];
async function loadCommunitySystems(){const [conf,gifs]=await Promise.all([api(`/api/guild/${gid()}/settings/confessions`),api(`/api/guild/${gid()}/settings/gif_actions`)]);$('#confess-enabled').checked=!!conf.enabled;$('#confess-channel').value=conf.channel_id||'';$('#confess-content').value=conf.content||'';$('#confess-title').value=conf.embed?.title||'Anonymous confession #{id}';$('#confess-color').value=conf.embed?.color||'#2b2d31';$('#confess-footer').value=conf.embed?.footer||'';$('#confess-submit-label').value=conf.submit_label||'Submit a confession';$('#confess-submit-emoji').value=conf.submit_emoji??'';$('#confess-reply-label').value=conf.reply_label||'Reply anonymously';$('#confess-reply-emoji').value=conf.reply_emoji??'';$('#confess-thread-name').value=conf.thread_name||'Confession #{id} replies';$('#confess-reply-title').value=conf.reply_title||'Anonymous reply #{reply_id}';$('#confess-reply-color').value=conf.reply_color||conf.embed?.color||'#2b2d31';$('#confess-reply-footer').value=conf.reply_footer||'Reply to confession #{id}';if($('#confess-image')){$('#confess-image').value=conf.embed?.image||'';$('#confess-thumb').value=conf.embed?.thumbnail||''}savedAssets.confessImage=conf.embed?.image_asset||'';savedAssets.confessThumb=conf.embed?.thumbnail_asset||'';if(savedAssets.confessImage)savedAssetPreviews.confessImage=`/api/guild/${gid()}/asset/${encodeURIComponent(savedAssets.confessImage)}`;if(savedAssets.confessThumb)savedAssetPreviews.confessThumb=`/api/guild/${gid()}/asset/${encodeURIComponent(savedAssets.confessThumb)}`;$('#gif-editors').innerHTML=gifActions.map(a=>`<div class="gif-action-editor"><div class="gif-action-head"><h3>/${a}</h3><label>Embed color<input type="color" id="gif-color-${a}" value="${escapeHtml(gifs._colors?.[a]||'#2b2d31')}"></label></div><div class="fields two"><label>Author name<input id="gif-author-${a}" value="${escapeHtml(gifs._authors?.[a]?.name||'')}"></label><label>Author icon URL<input id="gif-author-icon-${a}" value="${escapeHtml(gifs._authors?.[a]?.icon||'')}"></label></div><label>GIF URLs<textarea id="gif-${a}" rows="3" placeholder="One direct GIF URL per line">${(gifs[a]||[]).filter(x=>typeof x==='string').join('\n')}</textarea></label></div>`).join('');$$('#social input,#social textarea').forEach(i=>i.addEventListener('input',renderSocialPreviews));renderSocialPreviews()}
function renderSocialPreviews(){if(!$('#confess-preview'))return;const buttons=[{label:$('#confess-submit-label').value||'Submit a confession',emoji:$('#confess-submit-emoji').value},{label:$('#confess-reply-label').value||'Reply anonymously',emoji:$('#confess-reply-emoji').value}];$('#confess-preview').innerHTML=discordPreview($('#confess-content').value,($('#confess-title').value||'Anonymous confession #{id}').replace('{id}','42'),'The confession will appear here.',buttons,{color:$('#confess-color').value,footer:$('#confess-footer').value,image:savedAssetPreviews.confessImage||$('#confess-image')?.value,thumbnail:savedAssetPreviews.confessThumb||$('#confess-thumb')?.value,...authorExtras('confess','confessAuthor')});$('#confess-reply-preview').innerHTML=`<p class="eyebrow preview-gap">THREAD REPLY PREVIEW</p>${discordPreview('',($('#confess-reply-title').value||'Anonymous reply #{reply_id}').replace('{reply_id}','7').replace('{id}','42'),'The anonymous reply will appear here.',[],{color:$('#confess-reply-color').value,footer:($('#confess-reply-footer').value||'Reply to confession #{id}').replace('{id}','42'),...authorExtras('confess-reply','confessReplyAuthor')})}`;const first=gifActions.map(a=>({a,url:($('#gif-'+a)?.value||'').split('\n').find(Boolean)||(uploadedGifs[a]||[]).find(x=>x.preview)?.preview})).find(x=>x.url);$('#gif-preview').innerHTML=first?discordPreview(`@User ${first.a}s @Member`,'','',[],{image:first.url,color:$(`#gif-color-${first.a}`)?.value||'#2b2d31',author:$(`#gif-author-${first.a}`)?.value||'',author_icon:$(`#gif-author-icon-${first.a}`)?.value||''}):'<p class="muted">Add a GIF URL or upload a GIF to see a preview.</p>'}
async function saveConfessions(){await api(`/api/guild/${gid()}/settings/confessions`,'PUT',{enabled:$('#confess-enabled').checked,channel_id:$('#confess-channel').value,content:$('#confess-content').value,submit_label:$('#confess-submit-label').value,submit_emoji:$('#confess-submit-emoji').value,reply_label:$('#confess-reply-label').value,reply_emoji:$('#confess-reply-emoji').value,thread_name:$('#confess-thread-name').value,reply_title:$('#confess-reply-title').value,reply_color:$('#confess-reply-color').value,reply_footer:$('#confess-reply-footer').value,reply_author:$('#confess-reply-author')?.value||'',reply_author_icon:$('#confess-reply-author-icon')?.value||'',reply_author_icon_asset:savedAssets.confessReplyAuthor||'',embed:{title:$('#confess-title').value,color:$('#confess-color').value,footer:$('#confess-footer').value,image:$('#confess-image')?.value||'',thumbnail:$('#confess-thumb')?.value||'',image_asset:savedAssets.confessImage,thumbnail_asset:savedAssets.confessThumb,...authorPayload('confess','confessAuthor')}});toast('Confessions saved')}
async function saveGifs(showToast=true){const data={_colors:{},_authors:{}};gifActions.forEach(a=>{data[a]=$('#gif-'+a).value.split('\n').map(x=>x.trim()).filter(Boolean).concat((uploadedGifs[a]||[]).map(x=>({asset:x.asset,name:x.name})));data._colors[a]=$(`#gif-color-${a}`).value;data._authors[a]={name:$(`#gif-author-${a}`)?.value||'',icon:$(`#gif-author-icon-${a}`)?.value||''}});await api(`/api/guild/${gid()}/settings/gif_actions`,'PUT',data);if(showToast)toast('GIF lists saved')}
function renderGifAssets(action){const box=$(`#gif-assets-${action}`);if(!box)return;box.innerHTML=(uploadedGifs[action]||[]).map((x,i)=>`<article class="saved-gif-card"><img src="${escapeHtml(x.preview||`/api/guild/${gid()}/asset/${encodeURIComponent(x.asset)}`)}" alt="${escapeHtml(x.name||action)}"><span>${escapeHtml(x.name||'Saved GIF')}</span><button type="button" class="danger-action" onclick="deleteSavedGif('${action}',${i})">Delete</button></article>`).join('')||'<p class="muted">No uploaded GIFs saved for this action.</p>'}
async function deleteSavedGif(action,index){const item=uploadedGifs[action]?.[index];if(!item||!await confirmAction(`Delete ${item.name||'this GIF'} from /${action}?`,'Delete saved GIF?'))return;uploadedGifs[action].splice(index,1);try{await saveGifs(false);if(item.asset)await api(`/api/guild/${gid()}/asset/${encodeURIComponent(item.asset)}`,'DELETE');renderGifAssets(action);renderSocialPreviews();toast('Saved GIF deleted')}catch(e){uploadedGifs[action].splice(index,0,item);renderGifAssets(action);toast(e.message)}}
function extraEmbedHtml(prefix,description=false){return `<div class="embed-extras"><h3 class="subhead">Embed appearance</h3><label>Embed title<input id="${prefix}-title"></label>${description?`<label>Embed description<textarea id="${prefix}-embed-description" rows="2"></textarea></label>`:''}<div class="fields two"><label>Color<input type="color" id="${prefix}-color" value="#5865f2"></label><label>Footer<input id="${prefix}-footer"></label></div><div class="fields two"><label>Author name<input id="${prefix}-author"></label><label>Author icon URL or file<input id="${prefix}-author-icon"></label></div><div class="fields two"><label>Large image URL or file<input id="${prefix}-image"></label><label>Thumbnail URL or file<input id="${prefix}-thumb"></label></div></div>`}
function installAuthorEditor(prefix,anchor,key){const target=$(anchor);if($('#'+prefix+'-author')||!target)return;const fields=document.createElement('div');fields.className='fields two embed-author-fields';fields.innerHTML=`<label>Author name<input id="${prefix}-author" placeholder="Optional name above title"></label><label>Author icon URL or file<input id="${prefix}-author-icon" placeholder="https://..."></label>`;const placement=target.closest('label')||target;placement.insertAdjacentElement('beforebegin',fields);fields.querySelectorAll('input').forEach(i=>i.addEventListener('input',()=>{renderTicketPreviews();renderRolePreview();renderCommunity();renderSocialPreviews();renderAboutsPreview()}));addSavedAssetPicker(prefix+'-author-icon',key)}
function installAllAuthorEditors(){[['ticket','#ticket-image','ticketAuthor'],['ticket-open','#ticket-open-image','ticketOpenAuthor'],['rr','#rr-image','roleAuthor'],['event','#event-preview','eventAuthor'],['confess','#confess-preview','confessAuthor'],['confess-reply','#confess-reply-preview','confessReplyAuthor'],['abouts','#abouts-image','aboutsAuthor']].forEach(x=>installAuthorEditor(...x))}
function createExtraEmbedEditors(){const configs=[['#community .panel','poll',true],['#giveaways .panel','giveaway',false],['#glue .panel','glue',true]];for(const [sel,prefix,desc] of configs){const panel=$(sel);if(!panel||$('#'+prefix+'-color'))continue;const holder=document.createElement('div');holder.innerHTML=extraEmbedHtml(prefix,desc);panel.insertBefore(holder,panel.querySelector('button:last-of-type'));addSavedAssetPicker(prefix+'-image',prefix+'Image');addSavedAssetPicker(prefix+'-thumb',prefix+'Thumb');addSavedAssetPicker(prefix+'-author-icon',prefix+'Author')}}
function installMessageButtons(){const panel=$('#embeds .panel');if(!panel||$('#message-buttons'))return;const wrap=document.createElement('div');wrap.innerHTML='<h3 class="subhead">Buttons</h3><div id="message-buttons" class="option-builder"></div><button type="button" class="secondary add-choice" onclick="addMessageButton()">+ Add button</button><h3 class="subhead">Dropdown components</h3><div id="message-menus" class="option-builder"></div><button type="button" class="secondary add-choice" onclick="addMessageMenu()">+ Add dropdown</button>';const anchor=$('#edit-message-id').closest('label');panel.insertBefore(wrap,anchor);const preview=document.createElement('div');preview.id='message-button-preview';$('#p-embed').insertAdjacentElement('afterend',preview)}
function addMessageButton(data={}){const row=document.createElement('div');row.className='builder-row message-button';row.innerHTML=`<button type="button" class="remove-option">×</button><div class="fields two"><label>Label<input class="btn-label" value="${escapeHtml(data.label||'Button')}"></label><label>Emoji<input class="btn-emoji" value="${escapeHtml(data.emoji||'')}"></label></div><div class="fields two"><label>Style<select class="btn-style"><option value="secondary">Gray</option><option value="primary">Blue</option><option value="success">Green</option><option value="danger">Red</option></select></label><label>Action<select class="btn-action"><option value="response">Send response</option><option value="link">Open link</option><option value="role">Toggle role</option><option value="confession_submit">Submit confession</option><option value="confession_reply">Reply to confession</option></select></label></div><label>Response, URL, or confession ID<input class="btn-value" value="${escapeHtml(data.response||data.url||data.confession_id||'')}"></label><div class="switch-row"><p>Private dismissible response</p><input type="checkbox" class="switch btn-ephemeral" ${data.ephemeral===false?'':'checked'}></div><label>Role<select class="btn-role">${roleOptions()}</select></label>`;row.querySelector('.btn-style').value=data.style||'secondary';row.querySelector('.btn-action').value=data.action||'response';row.querySelector('.btn-role').value=data.role_id||'';row.querySelector('.remove-option').onclick=()=>{row.remove();renderMessageButtons()};row.querySelectorAll('input,select').forEach(i=>i.oninput=renderMessageButtons);$('#message-buttons').append(row);renderMessageButtons()}
function addMessageMenu(data={}){const available=Math.max(0,5-Math.ceil(messageButtons().length/5));if($$('.message-menu').length>=available)return toast('Discord has no more component rows available');const row=document.createElement('div');row.className='builder-row message-menu';row.innerHTML=`<button type="button" class="remove-option">×</button><label>Dropdown placeholder<input class="menu-placeholder" maxlength="150" value="${escapeHtml(data.placeholder||'Choose a topic')}"></label><div class="menu-options option-builder"></div><button type="button" class="secondary add-choice add-menu-option">+ Add dropdown option</button>`;row.querySelector('.remove-option').onclick=()=>{row.remove();renderMessageButtons()};row.querySelector('.add-menu-option').onclick=()=>addMessageMenuOption(row);row.querySelector('.menu-placeholder').oninput=renderMessageButtons;$('#message-menus').append(row);(data.options?.length?data.options:[{}]).forEach(o=>addMessageMenuOption(row,o));renderMessageButtons()}
function addMessageMenuOption(menu,data={}){if(menu.querySelectorAll('.message-menu-option').length>=25)return toast('Discord allows 25 options per dropdown');const row=document.createElement('div');row.className='builder-row message-menu-option';row.innerHTML=`<button type="button" class="remove-option">×</button><div class="fields two"><label>Option label<input class="menu-label" maxlength="100" value="${escapeHtml(data.label||'About us')}"></label><label>Emoji<input class="menu-emoji" value="${escapeHtml(data.emoji||'')}"></label></div><label>Short menu description<input class="menu-description" maxlength="100" value="${escapeHtml(data.description||'Learn more')}"></label><label>Response message<textarea class="menu-response" rows="3">${escapeHtml(data.response||'')}</textarea></label><div class="switch-row"><p>Private dismissible message</p><input type="checkbox" class="switch menu-ephemeral" ${data.ephemeral===false?'':'checked'}></div>`;row.querySelector('.remove-option').onclick=()=>{row.remove();renderMessageButtons()};row.querySelectorAll('input,textarea').forEach(i=>i.oninput=renderMessageButtons);menu.querySelector('.menu-options').append(row);renderMessageButtons()}
function messageMenus(){return $$('.message-menu').map(menu=>({placeholder:menu.querySelector('.menu-placeholder').value,options:[...menu.querySelectorAll('.message-menu-option')].map(r=>({label:r.querySelector('.menu-label').value,emoji:r.querySelector('.menu-emoji').value,description:r.querySelector('.menu-description').value,response:r.querySelector('.menu-response').value,ephemeral:r.querySelector('.menu-ephemeral').checked}))})).filter(m=>m.options.length)}
function messageButtons(){return $$('.message-button').map(r=>{const action=r.querySelector('.btn-action').value,value=r.querySelector('.btn-value').value;return{label:r.querySelector('.btn-label').value,emoji:r.querySelector('.btn-emoji').value,style:r.querySelector('.btn-style').value,action,response:action==='response'?value:'',url:action==='link'?value:'',confession_id:action==='confession_reply'?value:'',role_id:r.querySelector('.btn-role').value,ephemeral:r.querySelector('.btn-ephemeral').checked}})}function componentsPreview(components={}){return componentRow(components.buttons||[])+(components.menus||[]).map(m=>`<div class="discord-select-preview">${renderDiscordText(m.placeholder||'Choose an option')}<span>⌄</span></div><div class="select-preview-options">${(m.options||[]).map(o=>`<div>${renderDiscordText(o.emoji)} <b>${escapeHtml(o.label)}</b><small>${escapeHtml(o.description)}${o.response?` · Response: ${escapeHtml(o.response)}`:''}</small></div>`).join('')}</div>`).join('')}function renderMessageButtons(){if($('#message-button-preview'))$('#message-button-preview').innerHTML=componentsPreview({buttons:messageButtons(),menus:messageMenus()})}
