function installGlueTemplate(){const panel=$('#glue .panel');if(!panel||$('#glue-template'))return;const wrap=document.createElement('div');wrap.innerHTML=`<h3 class="subhead">Optional copy template</h3><div class="switch-row"><p>Show a button under the glued message</p><input type="checkbox" id="glue-template-enabled" class="switch"></div><div class="fields two"><label>Button label<input id="glue-button-label" value="Show template"></label><label>Button emoji<input id="glue-button-emoji"></label></div><label>Template<textarea id="glue-template" rows="13"></textarea></label><div class="actions"><button type="button" class="secondary" id="use-about-template">Add about-me template</button><button type="button" class="secondary" id="copy-glue-template">Copy template now</button></div>`;panel.insertBefore(wrap,panel.querySelector('button:last-of-type'));$('#use-about-template').onclick=()=>{$('#glue-template').value="╭ ╴╴╴╴╴╴╴· · ♰ · · ╴╴╴╴╴╴╴╮\ǹ̗ཐི^.  ̞.^ཋྀ about me:\n 𓋹┇name:\n 𓋹┇age: \n 𓋹┇pronouns: \n 𓋹┇sexuality (optional) :\n 𓋹┇languages (optional) : \n╰ ╴╴╴╴╴╴╴· · ♰ · · ╴╴╴╴╴╴╴╯\n\n╭ ╴╴╴╴╴╴╴· · ♰ · · ╴╴╴╴╴╴╴╮\ǹ̗ཐི^.  ̞.^ཋྀ my favorite: \n 𓋹┇color: \n 𓋹┇game:\n 𓋹┇hobby: \n 𓋹┇animal:\n 𓋹┇extra: \n╰ ╴╴╴╴╴╴╴· · ♰ · · ╴╴╴╴╴╴╴╯";$('#glue-template').dispatchEvent(new Event('input',{bubbles:true}))};$('#copy-glue-template').onclick=()=>navigator.clipboard.writeText($('#glue-template').value).then(()=>toast('Template copied'))}
function installGiveawayEmoji(){const panel=$('#giveaways .panel');if(!panel||$('#giveaway-emoji'))return;const label=document.createElement('label');label.innerHTML='Entry emoji<input id="giveaway-emoji" value="🎉" placeholder="Unicode or <:name:id>">';$('#giveaway-winners').closest('.fields').insertAdjacentElement('afterend',label)}
