function attachOtherPreviews(){const specs=[['giveaways',()=>{const emoji=$('#giveaway-emoji')?.value||'🎉';return discordPreview('', $('#giveaway-title').value||`Giveaway: ${$('#giveaway-prize').value||'Prize'}`,`React with ${emoji} to enter · ${$('#giveaway-winners').value||1} winner(s)`,[{label:'0 entries',emoji}],{color:$('#giveaway-color').value,image:savedAssetPreviews.giveawayImage||$('#giveaway-image').value,thumbnail:savedAssetPreviews.giveawayThumb||$('#giveaway-thumb').value,footer:$('#giveaway-footer').value,...authorExtras('giveaway','giveawayAuthor')})}],['glue',()=>discordPreview($('#glue-content').value,$('#glue-title').value,$('#glue-embed-description').value,$('#glue-template-enabled')?.checked?[{label:$('#glue-button-label').value||'Show template',emoji:$('#glue-button-emoji').value}]:[],{color:$('#glue-color').value,image:savedAssetPreviews.glueImage||$('#glue-image').value,thumbnail:savedAssetPreviews.glueThumb||$('#glue-thumb').value,footer:$('#glue-footer').value,...authorExtras('glue','glueAuthor')})]];for(const [id,draw] of specs){const page=$('#'+id),panel=page?.querySelector('.panel');if(!panel||page.querySelector('.section-live-preview'))continue;const box=document.createElement('div');box.className='section-live-preview';panel.insertAdjacentElement('afterend',box);const render=()=>box.innerHTML=`<p class="eyebrow">DISCORD PREVIEW</p>${draw()}`;page.querySelectorAll('input,textarea').forEach(i=>i.addEventListener('input',render));render()}}
function restoreDrafts(){$$('input[id],textarea[id],select[id]').forEach(el=>{if(['password','file'].includes(el.type))return;const key=`draft:${gid()}:${el.id}`,saved=localStorage.getItem(key);if(saved!==null&&el.type!=='color'){if(el.type==='checkbox')el.checked=saved==='true';else el.value=saved}const persist=()=>localStorage.setItem(key,el.type==='checkbox'?String(el.checked):el.value);el.addEventListener('input',persist);el.addEventListener('change',persist)})}
function addAboutOption(data={}){if($$('.about-option').length>=25)return toast('Discord allows 25 options');const row=document.createElement('div');row.className='builder-row about-option';row.innerHTML=`<button type="button" class="remove-option">×</button><div class="fields two"><label>Option label<input class="about-label" maxlength="100" value="${escapeHtml(data.label||'About us')}"></label><label>Emoji<input class="about-emoji" value="${escapeHtml(data.emoji||'')}"></label></div><label>Short dropdown description<input class="about-option-description" maxlength="100" value="${escapeHtml(data.description||'Learn about us')}"></label><label>Private dismissible message<textarea class="about-response" rows="4">${escapeHtml(data.response||'About us - we built this server today!')}</textarea></label>`;row.querySelector('.remove-option').onclick=()=>{row.remove();renderAboutsPreview()};row.querySelectorAll('input,textarea').forEach(i=>i.addEventListener('input',renderAboutsPreview));$('#abouts-options').append(row);renderAboutsPreview()}
