function renderAboutsPreview(){if(!$('#abouts-preview'))return;const options=aboutOptions(),first=options[0],menu=`<div class="discord-select-preview">${renderDiscordText($('#abouts-placeholder').value||'Choose a topic')}<span>⌄</span></div><div class="select-preview-options">${options.map(o=>`<div>${renderDiscordText(o.emoji)} <b>${escapeHtml(o.label)}</b><small>${escapeHtml(o.description)}</small></div>`).join('')}</div>`;$('#abouts-preview').innerHTML=`<p class="eyebrow">DISCORD PREVIEW</p>${discordPreview($('#abouts-content').value,$('#abouts-title').value,$('#abouts-description').value,[],{color:$('#abouts-color').value,image:savedAssetPreviews.aboutsImage||$('#abouts-image').value,thumbnail:savedAssetPreviews.aboutsThumb||$('#abouts-thumb').value,footer:$('#abouts-footer').value,components:menu})}${first?`<p class="eyebrow preview-gap">PRIVATE DISMISSIBLE RESPONSE PREVIEW</p>${ephemeralPreview(first.response)}`:''}`}
async function loadAbouts(){if(!$('#abouts-options'))return;const d=await api(`/api/guild/${gid()}/settings/abouts`);$('#abouts-channel').value=d.channel_id||$('#abouts-channel').value;$('#abouts-content').value=d.content||'';$('#abouts-title').value=d.embed?.title||'About this server';$('#abouts-description').value=d.embed?.description||'Choose an option below to learn more.';$('#abouts-color').value=d.embed?.color||'#b8343f';$('#abouts-footer').value=d.embed?.footer||'';$('#abouts-image').value=d.embed?.image||'';$('#abouts-thumb').value=d.embed?.thumbnail||'';$('#abouts-placeholder').value=d.placeholder||'Choose a topic';savedAssets.aboutsImage=d.image_asset||'';savedAssets.aboutsThumb=d.thumbnail_asset||'';$('#abouts-options').innerHTML='';(d.options?.length?d.options:[{}]).forEach(addAboutOption);renderAboutsPreview()}
async function publishAbouts(){const options=aboutOptions();if(!options.length)return toast('Add at least one Abouts option');const payload={channel_id:$('#abouts-channel').value,content:$('#abouts-content').value,embed:{title:$('#abouts-title').value,description:$('#abouts-description').value,color:$('#abouts-color').value,footer:$('#abouts-footer').value,image:$('#abouts-image').value,thumbnail:$('#abouts-thumb').value},placeholder:$('#abouts-placeholder').value,options,image_asset:savedAssets.aboutsImage||'',thumbnail_asset:savedAssets.aboutsThumb||''};try{await api(`/api/guild/${gid()}/settings/abouts`,'PUT',payload);await api(`/api/guild/${gid()}/embed/send`,'POST',{channel_id:payload.channel_id,content:payload.content,embed:payload.embed,asset_token:payload.image_asset,thumbnail_asset_token:payload.thumbnail_asset,menus:[{placeholder:payload.placeholder,options}]});toast('Abouts published')}catch(e){toast(e.message)}}
let botEmbedCache=[],botEmbedLoading=false,botEmbedLoadedGuild='';function renderBotEmbedCache(){const box=$('#bot-embed-list');if(!box)return;box.innerHTML=botEmbedCache.map((m,i)=>`<article class="bot-embed-card"><div><p class="eyebrow">#${escapeHtml(m.channel_name)} · ${new Date(m.created_at).toLocaleString()}</p>${discordPreview(m.content,m.embed.title,m.embed.description,[],{color:m.embed.color,image:m.embed.image,thumbnail:m.embed.thumbnail,author:m.embed.author,author_icon:m.embed.author_icon,footer:m.embed.footer,components:componentsPreview(m.components)})}</div><div class="actions"><button type="button" onclick="editBotEmbed(${i})">Edit in message editor</button><button type="button" class="danger-action" onclick="deleteBotEmbed(${i})">Delete message</button><a href="${m.jump_url}" target="_blank" rel="noopener">View in Discord</a></div></article>`).join('')||'<p class="muted">No recent bot embeds were found in channels the bot can read.</p>'}
async function loadBotEmbeds(rescan=false){const box=$('#bot-embed-list'),button=$('#bot-embeds-refresh');if(!box||botEmbedLoading)return;botEmbedLoading=true;button.disabled=true;let progress=1;button.textContent=rescan?'Scanning 1%':'Loading index';const timer=rescan?setInterval(()=>{if(progress<95){progress++;button.textContent=`Scanning ${progress}%`}},70):null;try{const x=await api(`/api/guild/${gid()}/bot-embeds${rescan?'?rescan=1':''}`);botEmbedCache=x.messages||[];botEmbedLoadedGuild=gid();renderBotEmbedCache();button.textContent=rescan?'Scanning 100%':'Index loaded';await wait(250)}catch(e){box.innerHTML=`<p class="alert">${escapeHtml(e.message)}</p>`;button.textContent='Load failed'}finally{if(timer)clearInterval(timer);botEmbedLoading=false;button.disabled=false;setTimeout(()=>button.textContent='Refresh bot embeds',400)}}
