function installSavedAssetPickers(){if(!$('#confess-image')&&$('#confess-preview')){const wrap=document.createElement('div');wrap.className='fields two';wrap.innerHTML='<label>Large image URL or file<input id="confess-image"></label><label>Thumbnail URL or file<input id="confess-thumb"></label>';$('#confess-preview').insertAdjacentElement('beforebegin',wrap);wrap.querySelectorAll('input').forEach(i=>i.addEventListener('input',renderSocialPreviews))}[["ticket-image","ticketImage"],["ticket-thumb","ticketThumb"],["ticket-open-image","ticketOpenImage"],["ticket-open-thumb","ticketOpenThumb"],["rr-image","roleImage"],["rr-thumb","roleThumb"],["confess-image","confessImage"],["confess-thumb","confessThumb"]].forEach(x=>addSavedAssetPicker(...x))}
let gifHydrated=false;async function enhanceGifUploaders(){if(!$('#gif-hug')||gifHydrated)return;gifHydrated=true;const saved=await api(`/api/guild/${gid()}/settings/gif_actions`);for(const action of gifActions){uploadedGifs[action]=(saved[action]||[]).filter(x=>typeof x==='object').map(x=>({...x,preview:`/api/guild/${gid()}/asset/${encodeURIComponent(x.asset)}`}));const area=$('#gif-'+action);area.value=(saved[action]||[]).filter(x=>typeof x==='string').join('\n');const input=document.createElement('input');input.type='file';input.accept='image/gif,image/webp,image/png';input.multiple=true;const gallery=document.createElement('div');gallery.id=`gif-assets-${action}`;gallery.className='saved-gif-list';input.onchange=async e=>{const files=[...e.target.files];for(const file of files){const x=await uploadSavedAsset(file,`gif-${action}-${Date.now()}-${file.name}`);uploadedGifs[action].push({asset:x.asset_token,name:file.name,preview:URL.createObjectURL(file)})}await saveGifs(false);renderGifAssets(action);renderSocialPreviews();input.value='';toast(`${files.length} file(s) saved to /${action}`)};area.insertAdjacentElement('afterend',input);input.insertAdjacentElement('afterend',gallery);renderGifAssets(action)}}
function enhanceFileDrop(input){if(input.dataset.dropReady||input.closest('.drop-zone'))return;input.dataset.dropReady='1';const surface=input.closest('label')||input.parentElement;if(!surface)return;surface.classList.add('universal-drop-zone');surface.addEventListener('dragover',e=>{e.preventDefault();e.stopPropagation();surface.classList.add('drop-active')});surface.addEventListener('dragleave',e=>{if(!surface.contains(e.relatedTarget))surface.classList.remove('drop-active')});surface.addEventListener('drop',e=>{e.preventDefault();e.stopPropagation();surface.classList.remove('drop-active');const files=[...e.dataTransfer.files];if(!files.length)return;const dt=new DataTransfer();files.forEach(file=>dt.items.add(file));input.files=dt.files;input.dispatchEvent(new Event('change',{bubbles:true}))})}
function enhanceAllFileDrops(){$$('input[type="file"]').forEach(enhanceFileDrop)}
