const dynamicObserver=new MutationObserver(()=>{installSavedAssetPickers();enhanceGifUploaders().catch(e=>toast(e.message));$$('.announcement-card').forEach((card,index)=>{if(card.dataset.uploadReady)return;card.dataset.uploadReady='1';for(const [selector,kind] of [['.ann-image','image'],['.ann-thumb','thumb']]){const base=card.querySelector(selector),input=document.createElement('input');input.type='file';input.accept='image/png,image/jpeg,image/gif,image/webp';input.onchange=async e=>{const x=await uploadSavedAsset(e.target.files[0],`announcement-${index}-${kind}`),url=URL.createObjectURL(e.target.files[0]);if(kind==='image')card.dataset.imageAsset=x.asset_token;else card.dataset.thumbAsset=x.asset_token;base.value=url;base.dispatchEvent(new Event('input',{bubbles:true}))};base.insertAdjacentElement('afterend',input)}});enhanceAllFileDrops()});dynamicObserver.observe(document.body,{childList:true,subtree:true});installSavedAssetPickers();enhanceAllFileDrops();
