async function loadArchives(){const box=$('#archive-list');box.innerHTML='<p class="muted">Loading archives…</p>';try{archiveCache=(await api(`/api/guild/${gid()}/archives`)).archives||[];box.innerHTML=archiveCache.map((a,i)=>`<article class="bot-embed-card"><div><p class="eyebrow">UPDATED ${new Date(a.updated_at).toLocaleString()}</p><h3>${escapeHtml(a.name)}</h3>${discordPreview(a.payload.content,a.payload.embed?.title,a.payload.embed?.description,[],{color:a.payload.embed?.color,image:a.payload.embed?.image,thumbnail:a.payload.embed?.thumbnail,author:a.payload.embed?.author,author_icon:a.payload.embed?.author_icon,footer:a.payload.embed?.footer})}</div><div class="actions"><button onclick="openArchive(${i})">Edit draft</button><button class="danger-action" onclick="deleteArchive(${i})">Delete</button></div></article>`).join('')||'<p class="muted">No archived drafts yet.</p>'}catch(e){box.innerHTML=`<p class="alert">${escapeHtml(e.message)}</p>`}}
function openArchive(i){const p=archiveCache[i]?.payload;if(!p)return;$('#embed-channel').value=p.channel_id||$('#embed-channel').value;$('#embed-content').value=p.content||'';for(const [id,key] of [['embed-title','title'],['embed-description','description'],['embed-color','color'],['embed-image','image'],['embed-thumb','thumbnail'],['embed-author','author'],['embed-author-icon','author_icon'],['embed-footer','footer']])if($('#'+id))$('#'+id).value=p.embed?.[key]||($('#'+id).type==='color'?'#5865f2':'');assetToken=p.asset_token||'';thumbnailAssetToken=p.thumbnail_asset_token||'';authorIconAssetToken=p.author_icon_asset_token||'';openPage('embeds');preview();toast('Archived draft opened')}
async function deleteArchive(i){const a=archiveCache[i];if(!a||!await confirmAction(`Delete archived draft “${a.name}”?`,'Delete archive?'))return;await api(`/api/guild/${gid()}/archives/${a.id}`,'DELETE');toast('Archive deleted');loadArchives()}

