const baseRenderAboutsPreview=renderAboutsPreview;renderAboutsPreview=function(){baseRenderAboutsPreview();const author=$('#abouts-author')?.value,icon=savedAssetPreviews.aboutsAuthor||$('#abouts-author-icon')?.value;if(!author)return;const embed=$('#abouts-preview .discord-embed');embed?.querySelector('h3')?.insertAdjacentHTML('beforebegin',`<div class="preview-embed-author">${icon?`<img src="${escapeHtml(icon)}" alt="">`:''}<b>${escapeHtml(author)}</b></div>`)};
