publishAbouts=async function(){const options=aboutOptions();if(!options.length)return toast('Add at least one Abouts option');const payload={channel_id:$('#abouts-channel').value,content:$('#abouts-content').value,embed:{title:$('#abouts-title').value,description:$('#abouts-description').value,color:$('#abouts-color').value,footer:$('#abouts-footer').value,image:$('#abouts-image').value,thumbnail:$('#abouts-thumb').value,...authorPayload('abouts','aboutsAuthor')},placeholder:$('#abouts-placeholder').value,options,image_asset:savedAssets.aboutsImage||'',thumbnail_asset:savedAssets.aboutsThumb||''};try{await api(`/api/guild/${gid()}/settings/abouts`,'PUT',payload);await api(`/api/guild/${gid()}/embed/send`,'POST',{channel_id:payload.channel_id,content:payload.content,embed:payload.embed,asset_token:payload.image_asset,thumbnail_asset_token:payload.thumbnail_asset,author_icon_asset_token:payload.embed.author_icon_asset,menus:[{placeholder:payload.placeholder,options}]});toast('Abouts published')}catch(e){toast(e.message)}};
const oldLoadGlueSettings=loadGlueSettings;loadGlueSettings=async function(){if(!$('#glue-channel'))return;try{const d=await api(`/api/guild/${gid()}/glue`),items=d.items||[];$('#glue-list').innerHTML=items.map(x=>`<article class="bot-embed-card"><div><p class="eyebrow">#${escapeHtml(x.channel_name)}</p><p>${escapeHtml(x.content||x.embed?.title||'Embed glue')}</p></div><button class="secondary" onclick="selectGlue('${x.channel_id}')">Edit</button></article>`).join('')||'<p class="muted">No glued channels yet.</p>';window.glueItems=items;selectGlue($('#glue-channel').value,false)}catch(e){toast(e.message)}};
function selectGlue(channelId,change=true){const d=(window.glueItems||[]).find(x=>x.channel_id===String(channelId));if(change)$('#glue-channel').value=channelId;if(!d)return;$('#glue-content').value=d.content||'';$('#glue-template-enabled').checked=!!d.template_enabled;$('#glue-template').value=d.template||'';$('#glue-button-label').value=d.button_label||'Show template';$('#glue-button-emoji').value=d.button_emoji||'';$('#glue-title').value=d.embed?.title||'';$('#glue-embed-description').value=d.embed?.description||'';$('#glue-color').value=d.embed?.color||'#5865f2';$('#glue-footer').value=d.embed?.footer||'';$('#glue-author').value=d.embed?.author||'';$('#glue-author-icon').value=d.embed?.author_icon||'';savedAssets.glueAuthor=d.embed?.author_icon_asset||'';$('#glue-image').value=d.embed?.image||'';$('#glue-thumb').value=d.embed?.thumbnail||'';$('#glue-content').dispatchEvent(new Event('input',{bubbles:true}))}
