let imageEdit={input:null,img:null,url:'',rect:null,action:null,start:null};
function buildImageEditor(){const modal=$('#image-editor-modal');if(!modal)return;modal.innerHTML=`<div class="confirm-dialog" role="dialog" aria-modal="true"><p class="eyebrow">IMAGE EDITOR</p><h2>Drag to crop or fit image</h2><p class="muted">Move the box over the image and drag any corner to resize it, just like a screenshot crop.</p><div class="image-editor-presets"><button type="button" class="secondary" data-preset="banner">Banner</button><button type="button" class="secondary" data-preset="wide">Wide</button><button type="button" class="secondary" data-preset="square">Square</button><button type="button" class="secondary" data-preset="full">Full image</button></div><div class="image-editor-stage" id="image-editor-stage"><img id="image-editor-source" alt="Image being edited"><div id="image-editor-crop"><i data-handle="nw"></i><i data-handle="ne"></i><i data-handle="sw"></i><i data-handle="se"></i></div></div><div class="image-editor-controls"><label>Result<select id="image-editor-mode"><option value="crop">Crop to my box</option><option value="fit">Fit whole image inside this shape</option></select></label><label>Fit background<input id="image-editor-background" type="color" value="#2b2d31"></label></div><div class="actions"><button class="secondary" type="button" onclick="closeImageEditor()">Cancel</button><button type="button" onclick="applyImageEdit()">Use edited image</button></div></div>`;modal.querySelectorAll('[data-preset]').forEach(b=>b.onclick=()=>setImageCropPreset(b.dataset.preset));const stage=$('#image-editor-stage');stage.onpointerdown=startImageCrop;window.addEventListener('pointermove',moveImageCrop);window.addEventListener('pointerup',()=>imageEdit.action=null);modal.addEventListener('pointerdown',e=>{if(e.target===modal)closeImageEditor()})}
function imageDisplayBounds(){const stage=$('#image-editor-stage'),iw=imageEdit.img.naturalWidth,ih=imageEdit.img.naturalHeight,scale=Math.min(stage.clientWidth/iw,stage.clientHeight/ih),w=iw*scale,h=ih*scale;return{x:(stage.clientWidth-w)/2,y:(stage.clientHeight-h)/2,w,h,scale}}
function paintImageCrop(){const box=$('#image-editor-crop'),r=imageEdit.rect;if(!box||!r)return;Object.assign(box.style,{left:r.x+'px',top:r.y+'px',width:r.w+'px',height:r.h+'px'})}
function setImageCropPreset(shape){if(!imageEdit.img)return;const b=imageDisplayBounds();if(shape==='full'){imageEdit.rect={x:b.x,y:b.y,w:b.w,h:b.h};return paintImageCrop()}const ratio=shape==='banner'?3:shape==='wide'?16/9:1;let w=b.w*.82,h=w/ratio;if(h>b.h*.82){h=b.h*.82;w=h*ratio}imageEdit.rect={x:b.x+(b.w-w)/2,y:b.y+(b.h-h)/2,w,h};paintImageCrop()}
function startImageCrop(e){if(!imageEdit.rect)return;const handle=e.target.dataset.handle,r=imageEdit.rect;imageEdit.action=handle||'move';imageEdit.start={x:e.clientX,y:e.clientY,rect:{...r}};e.currentTarget.setPointerCapture?.(e.pointerId);e.preventDefault()}
function moveImageCrop(e){if(!imageEdit.action||!imageEdit.start)return;const b=imageDisplayBounds(),s=imageEdit.start,r={...s.rect},dx=e.clientX-s.x,dy=e.clientY-s.y,min=36,a=imageEdit.action;if(a==='move'){r.x+=dx;r.y+=dy}else{if(a.includes('w')){r.x+=dx;r.w-=dx}if(a.includes('e'))r.w+=dx;if(a.includes('n')){r.y+=dy;r.h-=dy}if(a.includes('s'))r.h+=dy;if(r.w<min){if(a.includes('w'))r.x-=min-r.w;r.w=min}if(r.h<min){if(a.includes('n'))r.y-=min-r.h;r.h=min}}r.w=Math.min(r.w,b.x+b.w-r.x);r.h=Math.min(r.h,b.y+b.h-r.y);r.x=Math.max(b.x,Math.min(r.x,b.x+b.w-r.w));r.y=Math.max(b.y,Math.min(r.y,b.y+b.h-r.h));imageEdit.rect=r;paintImageCrop();e.preventDefault()}
function openImageEditor(input,file){if(file.type==='image/gif'){input.dataset.edited='1';input.dispatchEvent(new Event('change',{bubbles:true}));return}const img=new Image(),url=URL.createObjectURL(file);img.onload=()=>{imageEdit={input,img,url,rect:null,action:null,start:null};$('#image-editor-source').src=url;$('#image-editor-modal').hidden=false;requestAnimationFrame(()=>setImageCropPreset(input.id.includes('thumb')||input.id.includes('author')?'square':'banner'))};img.src=url}
function closeImageEditor(){if(imageEdit.url)URL.revokeObjectURL(imageEdit.url);$('#image-editor-modal').hidden=true;imageEdit={input:null,img:null,url:'',rect:null,action:null,start:null}}
function applyImageEdit(){const input=imageEdit.input,r=imageEdit.rect,b=imageDisplayBounds();if(!input||!r)return;const ratio=r.w/r.h,w=Math.max(1,Math.round(Math.min(1600,imageEdit.img.naturalWidth))),h=Math.max(1,Math.round(w/ratio)),canvas=document.createElement('canvas');canvas.width=w;canvas.height=h;const g=canvas.getContext('2d');if($('#image-editor-mode').value==='fit'){g.fillStyle=$('#image-editor-background').value;g.fillRect(0,0,w,h);const scale=Math.min(w/imageEdit.img.naturalWidth,h/imageEdit.img.naturalHeight),dw=imageEdit.img.naturalWidth*scale,dh=imageEdit.img.naturalHeight*scale;g.drawImage(imageEdit.img,(w-dw)/2,(h-dh)/2,dw,dh)}else{const sx=(r.x-b.x)/b.scale,sy=(r.y-b.y)/b.scale,sw=r.w/b.scale,sh=r.h/b.scale;g.drawImage(imageEdit.img,sx,sy,sw,sh,0,0,w,h)}canvas.toBlob(blob=>{if(!blob)return toast('Could not create the edited image');const dt=new DataTransfer();dt.items.add(new File([blob],(input.files[0]?.name||'image').replace(/\.[^.]+$/,'.png'),{type:'image/png'}));input.dataset.edited='1';input.files=dt.files;closeImageEditor();input.dispatchEvent(new Event('change',{bubbles:true}))},'image/png',.92)}
document.addEventListener('change',e=>{const input=e.target;if(input.matches?.('input[type="file"][accept*="image"]')&&input.files[0]&&!input.dataset.edited){e.stopImmediatePropagation();openImageEditor(input,input.files[0])}else if(input.dataset?.edited)delete input.dataset.edited},true);buildImageEditor();

function renderAdvancedAnnouncementPreview(card){const box=card.querySelector('.mini-preview');if(!box)return;box.innerHTML=discordPreview(card.querySelector('.ann-content')?.value||'',card.querySelector('.ann-title')?.value||'',card.querySelector('.ann-description')?.value||'',[],{color:card.querySelector('.ann-color')?.value||'#5865f2',footer:card.querySelector('.ann-footer')?.value||'',image:card.querySelector('.ann-image')?.value||'',thumbnail:card.querySelector('.ann-thumb')?.value||'',author:card.querySelector('.ann-author')?.value||'',author_icon:card.querySelector('.ann-author-icon')?.value||''})}
function enhanceAnnouncementCards(){const cards=$$('.announcement-card'),keys=['welcome','leave','boost','birthdays'];cards.forEach((card,index)=>{if(card.dataset.advancedEmbed)return;card.dataset.advancedEmbed='1';const key=keys[index],author=card.querySelector('.ann-author');if(author){const field=document.createElement('label');field.innerHTML='Author icon URL<input class="ann-author-icon" placeholder="https://...">';author.closest('label').insertAdjacentElement('afterend',field)}let tracking=null;if(index===0){tracking=document.createElement('div');tracking.className='invite-tracking-fields';tracking.innerHTML='<div class="switch-row"><p>Invite tracking</p><input class="ann-invite-tracking switch" type="checkbox"></div><label>Custom invite message<input class="ann-invite-message" value="Invited by {inviter} using {invite_code} ({invite_uses} uses)"></label><p class="muted">Variables: {inviter}, {invite_code}, {invite_uses}. Jane Doe needs Manage Server to read invite uses.</p>';card.querySelector('label')?.insertAdjacentElement('afterend',tracking)}card.querySelectorAll('input,textarea').forEach(i=>i.addEventListener('input',()=>renderAdvancedAnnouncementPreview(card)));api(`/api/guild/${gid()}/settings/${key}`).then(d=>{if(tracking){tracking.querySelector('.ann-invite-tracking').checked=!!d.invite_tracking;tracking.querySelector('.ann-invite-message').value=d.invite_message||tracking.querySelector('.ann-invite-message').value}card.querySelector('.ann-author-icon').value=d.embed?.author_icon||'';renderAdvancedAnnouncementPreview(card)});const save=card.querySelector('button:last-child');save?.addEventListener('click',async()=>{const old=await api(`/api/guild/${gid()}/settings/${key}`);old.invite_tracking=card.querySelector('.ann-invite-tracking')?.checked||false;old.invite_message=card.querySelector('.ann-invite-message')?.value||'';old.embed={...(old.embed||{}),author_icon:card.querySelector('.ann-author-icon')?.value||''};await api(`/api/guild/${gid()}/settings/${key}`,'PUT',old)}) ;renderAdvancedAnnouncementPreview(card)})}
const announcementEnhancer=new MutationObserver(enhanceAnnouncementCards);announcementEnhancer.observe($('#announcement-cards'),{childList:true});enhanceAnnouncementCards();
